<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8"/>
<title>Reputation</title>
<link href="https://fonts.googleapis.com/css2?family=Cinzel:wght@400;500;600;700&family=Spectral:ital,wght@0,400;0,500;1,400&family=Inter:wght@300;400;500;600&display=swap" rel="stylesheet"/>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
html,body{background:transparent;font-family:'Inter',sans-serif}
:root{--card:#0f0e0c;--sec:#16140f;--bd:#2b2619;--bd2:#3b372a;--t1:#efe7d2;--t2:#a89a72;--t3:#776e57;
  --gold:#cda64e;--gold-dim:#8a6f33;--gold-bg:rgba(205,166,78,0.09);
  --grn:#6fae7a;--grn-bg:rgba(111,174,122,0.14);--red:#c45a4f;--red-bg:rgba(196,90,79,0.14);
  --fh:'Cinzel',serif;--ft:'Spectral',serif;}
html.lt{--card:#fffdf8;--sec:#f6f1e5;--bd:#e4dabf;--bd2:#d6c8a0;--t1:#1c1a13;--t2:#5b5340;--t3:#8c8266;
  --gold:#9c7a20;--gold-dim:#b69440;--gold-bg:rgba(156,122,32,0.08);
  --grn:#3f7d4c;--grn-bg:rgba(63,125,76,0.12);--red:#b03a30;--red-bg:rgba(176,58,48,0.1);}
svg{display:block}
.card{max-width:480px;margin:9px auto;background:var(--card);border:1px solid var(--bd2);border-left:3px solid var(--gold);padding:11px 13px;position:relative}
.card+.card{margin-top:8px}
.top{display:flex;align-items:center;gap:9px}
.who{display:flex;flex-direction:column;min-width:0;flex:1}
