.delta{display:flex;align-items:center;gap:5px;font-family:var(--fh);font-size:13px;font-weight:700;padding:3px 9px;border:1px solid;white-space:nowrap;flex-shrink:0}
.delta svg{width:13px;height:13px;stroke:currentColor;fill:none;stroke-width:2.5}
.delta.up{color:var(--grn);border-color:var(--grn);background:var(--grn-bg)}
.delta.down{color:var(--red);border-color:var(--red);background:var(--red-bg)}
