</head>
<body>
<textarea id="raw" style="display:none;position:absolute;left:-9999px;">$1</textarea>
<div id="root"></div>
<script>
(function(){
  function g(id){return document.getElementById(id);}
  var raw=(g('raw').value||'').replace(/<\/?MT_REP>/gi,'').trim();
  var D={}; try{ if(raw && raw.charAt(0)==='{') D=JSON.parse(raw);}catch(e){}
  var th=(D.ui_lang==='th');
  if(D.ui_theme==='light') document.documentElement.classList.add('lt');
  function esc(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
  var list = Array.isArray(D.changes)?D.changes : (Array.isArray(D)?D : [D]);
  var UP='<svg viewBox="0 0 24 24"><polyline points="6 15 12 9 18 15"/></svg>';
  var DN='<svg viewBox="0 0 24 24"><polyline points="6 9 12 15 18 9"/></svg>';
  var EQ='<svg viewBox="0 0 24 24"><line x1="5" y1="12" x2="19" y2="12"/></svg>';
  var html='';
  list.forEach(function(r){
    if(!r || (!r.npc && !r.name)) return;
    var ch=String(r.change!=null?r.change:'').trim();
    var lc=ch.toLowerCase();
    var dir='flat', ic=EQ;
    if(/^-/.test(ch)||/down|worse|lower|neg|drop|fall/.test(lc)){dir='down';ic=DN;}
    else if(/^\+/.test(ch)||/up|better|higher|pos|rise|gain/.test(lc)||(/^\d/.test(ch)&&parseInt(ch,10)>0)){dir='up';ic=UP;}
    var chTxt = ch || (dir==='up'?(th?'ดีขึ้น':'Up'):dir==='down'?(th?'แย่ลง':'Down'):(th?'คงเดิม':'—'));
    html+='<div class="card"><div class="top"><div class="who"><span class="lbl">'+(th?'ความสัมพันธ์':'Reputation')+'</span><span class="nm">'+esc(r.npc||r.name)+'</span></div>';
    html+='<span class="delta '+dir+'">'+ic+esc(chTxt)+'</span></div>';
    if(r.standing) html+='<div class="stand"><span class="lbl">'+(th?'สถานะ':'Standing')+'</span><span class="stand-chip">'+esc(r.standing)+'</span></div>';
    html+='</div>';
  });
  g('root').innerHTML= html || '';
})();
</script>
</body>
</html>
